import boto3
from botocore.exceptions import ClientError
import json

# SQS Queue URL
sqs_queue_url = 'https://sqs.us-east-1.amazonaws.com/123456789012/myqueue'

# Initialize SQS client
sqs = boto3.client('sqs')

def process_message(message):
    try:
        # Parse message body as JSON
        data = json.loads(message['Body'])
        
        # Determine action based on message type
        if 'type' in data and data['type'] == 'job':
            job_id = data['id']
            # Execute job processing logic here
            print(f"Processing job {job_id}")
        elif 'type' in data and data['type'] == 'report':
            report_data = data['data']
            # Process report data here
            print(f"Processing report: {report_data}")
        
    except json.JSONDecodeError as e:
        print(f"Invalid JSON message: {message['Body']}")
    except KeyError as e:
        print(f"Missing key in message: {e}")

def poll_sqs_queue():
    try:
        # Poll SQS queue for messages
        response = sqs.receive_message(
            QueueUrl=sqs_queue_url,
            MaxNumberOfMessages=10,
            WaitTimeSeconds=20
        )
        
        if 'Messages' in response:
            for message in response['Messages']:
                process_message(message)
                
                # Delete processed message from SQS queue
                sqs.delete_message(
                    QueueUrl=sqs_queue_url,
                    ReceiptHandle=message['ReceiptHandle']
                )
    
    except ClientError as e:
        print(f"SQS error: {e}")

if __name__ == "__main__":
    while True:
        poll_sqs_queue()